      ->fields('my_table', ['id', 'title'])
      ->execute()
      ->fetchAll();
  }
}
```

Key points:
- `readonly` prevents reassignment of properties after construction.
- `private readonly` is preferred over `protected`/`public` for encapsulation.
- Always use `declare(strict_types=1);` at the top of the file.
- Type-hint interfaces (e.g., `ConfigFactoryInterface`) — *not* concrete classes — in constructors for testability and DI flexibility.
- Avoid `mixed` — Drupal core now uses full type hints in PHP 8.3+ services.

This aligns with [Symfony 6 DI best practices](https://symfony.com/doc/current/service-container.html#constructor-injection) and Drupal 11’s PHP 8.3 requirements.

In Drupal 11, use PHP 8.1+ **union types** in your plugin class constructor or method signatures to accept `string|array<string>`. Avoid encoding types in docblocks alone — use runtime-enforced union types.

Example plugin class with union type:
```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Plugin\MyPlugin;

use Drupal\Core\Plugin\PluginBase;
use Drupal\Core\Plugin\PluginFormInterface;

#[\Drupal\Core\Plugin\Plugin(
  id: "my_plugin",
  admin_label: @Translation("My Plugin")
)]
class MyPlugin extends PluginBase implements PluginFormInterface {

  public function __construct(
    private readonly array $configuration,
    private readonly string|array $allowedValues // Union type
  ) {
    // Validate at construction time
    if (is_string($allowedValues)) {
      $allowedValues = [$allowedValues];
    }
    $this->allowedValues = $allowedValues;
  }

  public function buildConfigurationForm(array $form, \Drupal\Core\Form\FormStateInterface $form_state): array {
    $form['value'] = [
      '#type' => 'select',
      '#options' => array_combine($this->allowedValues, $this->allowedValues),
      '#default_value' => $this->configuration['value'] ?? '';
    ];
    return $form;
  }
}
```

Service registration in `my_module.services.yml`:
```yaml
services:
  my_module.my_service:
    class: Drupal\my_module\Service\MyService
    arguments:
      $allowedValues: ['foo', 'bar', 'baz'] # array<string>
# OR
      $allowedValues: 'single_value'         # string — will be cast to ['single_value'] in constructor
```

Best practices:
- Prefer `string|array<string>` over `mixed`.
- Validate and normalize union inputs early (e.g., in constructor).
- Use `is_string()`/`is_array()` checks before casting to avoid runtime errors.
- Avoid union types in plugin *annotations* — they’re not evaluated at runtime by PHP; instead, enforce them in PHP code.

