For a controller using union types and PHP 8 attributes (Symfony 6.3+):

```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Controller;

use Drupal\Core\Controller\ControllerBase;
use Symfony\Component\Routing\Annotation\Route;

final class NodeController extends ControllerBase {
  #[Route(
    path: '/node/{node}',
    methods: ['GET'],
    defaults: [
      '_controller' => self::class . '::view',
    ],
  )]
  public function view(int|mixed $node): array {
    if ($node instanceof \Drupal\Core\Entity\EntityInterface) {
      return ['#markup' => 'Node entity passed'];
    }

    // Explicitly cast or validate
    /** @var int $node_id */
    $node_id = (int) ($node ?? 0);

    $node_storage = $this->entityTypeManager()->getStorage('node');
    $node_entity = $node_storage->load($node_id);

    if (!$node_entity) {
      throw new \Symfony\Component\HttpKernel\Exception\NotFoundHttpException();
    }

    return [
      '#theme' => 'node',
      '#node' => $node_entity,
      '#view_mode' => 'full',
