      $this->entityTypeManager,
      $this->database,
      $format,
    );
  }
}
```

**ReportGenerator.php:**
```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Report;

class ReportGenerator {
  public function __construct(
    private readonly EntityTypeManagerInterface $entityTypeManager,
    private readonly Connection $database,
    private readonly string $format,
  ) {}

  public function generate(): string {
    // ...
  }
}
```

✅ Benefits:
- All types declared (`string`, `Connection`, `EntityTypeManagerInterface`)
- `readonly` ensures immutability
- Factory pattern decouples construction
- No `mixed` or `array` fallbacks

⚠️ Avoid: `arguments: ['@service']` without `factory`, or omitting `declare(strict_types=1)`.

No — Drupal’s route system does **not** support PHP 8 attributes for route definitions. Route subscribers must extend `RouteSubscriberBase` and override `alterRoutes()`.

✅ Correct pattern (PHP 8.3):

```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\EventSubscriber;

use Drupal\Core\RouteSubscriber\RouteSubscriberBase;
use Symfony\Component\Routing\RouteCollection;

class MyRouteSubscriber extends RouteSubscriberBase {

  protected function alterRoutes(RouteCollection $collection): void {
    if ($route = $collection->get('entity.node.canonical')) {
      $route->setDefault('_access', 'TRUE');
    }
  }
}
```

✅ Service registration (`my_module.services.yml`):
```yaml
services:
  my_module.route_subscriber:
    class: Drupal\my_module\EventSubscriber\MyRouteSubscriber
    tags:
      - { name: event_subscriber }
```

❌ Incorrect: `#[RouteSubscriber]` or `#[Route(name='...', path='...')]` — those are Symfony annotations or attributes for *annotations-based routing*, which Drupal 10/11 has deprecated in favor of explicit route subscribers for programmatic control.

However, PHP 8 attributes **are** supported for:
- Plugin definitions (e.g., `#[Plugin(
    id: "my_plugin",
    ...
  )]`)
- Service factory methods (e.g., `#[Autowire(service: 'my_service')]`)
- Custom attributes for dependency injection (e.g., `#[Required]`)

So: use attributes where Symfony/Drupal 11 explicitly supports them — but *not* for route definition.

In Drupal 11 on PHP 8.3, use constructor property promotion with strict typing and explicit `?` for nullable/optional parameters. Always enable `declare(strict_types=1);` in the file.

**Correct pattern:**
```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Service;

use Drupal\core\Config\ConfigFactoryInterface;
use Drupal\my_module\Exception\InvalidConfigurationException;

class MyService
{
  public function __construct(
    private readonly ConfigFactoryInterface $configFactory,
    private ?string $customSetting = null,
  ) {
    if ($customSetting !== null && strlen($customSetting) > 255) {
      throw new InvalidConfigurationException('Custom setting must be ≤255 characters.');
    }
  }

  public function getCustomSetting(): ?string
  {
    return $this->customSetting;
  }
}
```

**Key points:**
- `readonly` enforces immutability after construction (PHP 8.1+).
- `?string` is the modern nullable syntax (not `string|null`).
- Services (e.g. `ConfigFactoryInterface`) must be non-nullable — omit `?`.
- Use explicit defaults (`= null`) for optional parameters; avoid omitting them.

**services.yml:**
```yaml
services:
  my_module.my_service:
    class: Drupal\my_module\Service\MyService
    arguments:
      - '@config.factory'
      - '%my_module.custom_setting%' # may be null in config
```

Avoid redundant types like `string|null|string` or `self|null` — these now cause compile-time errors in PHP 8.3+.

In Drupal 11, use PHP 8 attributes (`#[Plugin(...)]`) on plugin base classes and combine them with constructor property promotion and strict typing.

**Example for a custom block plugin:**
```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Plugin\Block;

use Drupal\block\Plugin\Block\BlockBase;
use Drupal\core\Plugin\PluginInspectionInterface;
use Drupal\core\form\FormStateInterface;

#[
  Plugin(
    id: 'my_custom_block',
    admin_label: @Translation('My Custom Block'),
    category: @Translation('Custom'),
  )
]
class MyCustomBlock extends BlockBase implements PluginInspectionInterface
{
  public function __construct(
    array $configuration,
    string $plugin_id,
    mixed $plugin_definition,
  ) {
    // Explicitly assign via parent to avoid duplicate logic
    parent::__construct($configuration, $plugin_id, $plugin_definition);
  }

  public function build(): array {
    return [
      '#markup' => $this->t('Hello from MyCustomBlock'),
    ];
  }

  public function blockForm($form, FormStateInterface $form_state): array {
    $form['custom_text'] = [
      '#type' => 'textfield',
      '#title' => $this->t('Custom text'),
      '#default_value' => $this->configuration['custom_text'] ?? '',
    ];
    return $form;
  }

  public function blockSubmit($form, FormStateInterface $form_state): void {
    $this->configuration['custom_text'] = $form_state->getValue('custom_text');
  }
}
```

**Important:**
- Use `mixed` only for `$plugin_definition` — it’s inherited from `PluginBase` and typed as `mixed` in core.
- Avoid `mixed` elsewhere; prefer union types (e.g. `string|int`), but in this case `mixed` is unavoidable.
- Always use named arguments in `@Translation()` calls for clarity and i18n tooling.
- `declare(strict_types=1);` is required in PHP 8.3+ for predictable behavior.

**Note:** Core plugins like `PluginBase` use `mixed` for historical reasons. Do not introduce `mixed` in your own signatures unless absolutely necessary.

Below is a fully typed, strict-mode route subscriber for Drupal 11 using union types, named arguments (via PHP 8 attributes), and WCAG-conscious defaults (e.g., `title` is required in route definitions for screen readers).

```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Routing;

use Drupal\core\RouteSubscriber\RouteSubscriberBase;
use Drupal\core\routing\RouteSubscriberInterface;
use Symfony\Component\Routing\Route;
use Symfony\Component\Routing\RouteCollection;

#[
  Service('my_module.route_subscriber'),
  Tag('event_subscriber')
]
class RouteSubscriber extends RouteSubscriberBase implements RouteSubscriberInterface
{
  protected function alterRoutes(RouteCollection $collection): void
  {
    // Example: enhance all route entities with cache metadata and accessibility defaults
    foreach ($collection->all() as $route) {
      // Ensure title is set — required for accessibility (SC 2.4.6 Headings and Labels)
      $defaults = $route->getDefaults();
      if (!isset($defaults['_title']) && !isset($defaults['_title_callback'])) {
        $route->setDefault('_title', $this->t('Untitled Page'));
      }

      // Add strict cache tags — avoids stale content for authenticated users
      $route->setOption('cache_tags', $route->getOption('cache_tags') ?? []);

      // Enable secure cookies for authenticated routes (SC 1.4.10 Reflow, SC 1.4.11 Non-text Contrast)
      if ($route->getDefault('_access') === 'TRUE') {
        $route->setOptions($route->getOptions() + [
          'options' => ['samesite' => 'Strict'],
        ]);
      }
    }
  }
}
```

**Alternative: Route enhancement with union types on a custom method**
```php
private function addA11yDefaults(Route $route): Route {
  $defaults = $route->getDefaults();

  if (isset($defaults['_entity_view']) && $defaults['_entity_view'] instanceof EntityRouteBuilderInterface) {
    $route->setDefault('_title_callback', static fn() => $this->t('View entity'));
  }

  // Ensure breadcrumb exists (SC 2.4.4 Link Purpose)
  $options = $route->getOptions();
  if (!isset($options['attributes']['aria-label'])) {
    $route->setOption('attributes', $options['attributes'] ?? [] + [
      'aria-label' => $route->getDefault('_title') ?? '',
    ]);
  }

  return $route;
}
```

**Key WCAG & typing notes:**
- `RouteSubscriberBase` is typed — no `mixed` in your code.
- Union types: use `Route|callable` only where Symfony’s API demands it (e.g., `_controller`).
- `string|null` → use `?string`.
- Always set `_title` for screen reader context (SC 2.4.6).
- Avoid empty route titles — they fail SC 2.4.6.
- Use `readonly` properties where applicable (e.g., in custom services).

In PHP 8.0+, you can use constructor property promotion with nullable types and a default value of `null`, but the `readonly` modifier must be applied *after* the visibility and *before* the type. For optional services in Drupal plugins, use `private readonly ?ServiceType $service = null;`.

Example for a custom block plugin:
```php
<?php

declare(strict_types=1);

namespace Drupal\example\Plugin\Block;

use Drupal\block\BlockBase;
use Drupal\Core\Plugin\ContainerFactoryPluginInterface;
use Symfony\Component\DependencyInjection\ContainerInterface;
use Drupal\example\Service\ReportGeneratorInterface;

class ReportBlock extends BlockBase implements ContainerFactoryPluginInterface {

  /**
   * @var ReportGeneratorInterface|null
   */
  private readonly ?ReportGeneratorInterface $reportGenerator;

  public function __construct(
    array $configuration,
    $plugin_id,
    $plugin_definition,
    private readonly ?ReportGeneratorInterface $reportGenerator = null
  ) {
    parent::__construct($configuration, $plugin_id, $plugin_definition);
  }

  public static function create(ContainerInterface $container, array $configuration, $plugin_id, $plugin_definition) {
    return new static(
      $configuration,
      $plugin_id,
      $plugin_definition,
      $container->has('example.report_generator') ? $container->get('example.report_generator') : null
    );
  }

  // …
}
```

Key points:
- Use `private readonly ?ReportGeneratorInterface $service = null` — the `?` goes *before* the type, `readonly` *after* visibility.
- In `create()`, use `$container->has()` before calling `$container->get()` to avoid autowiring errors for optional services.
- Do *not* reassign the property in the body — it’s immutable.
- Strict `declare(strict_types=1)` is required for type safety in Drupal 11.

In Drupal 11 (Symfony 6), replace `@Route` annotations with `#[Route]` PHP 8 attributes. Use `#[Route]` on the controller method, and ensure the path, methods, and requirements match the original.

**Before (annotation-based, deprecated in Drupal 11):**
```php
/**
 * @package Drupal\example
 *
 * @Route("/example/report/{id}",
 *   methods = {"GET"},
 *   requirements = {
 *     "id" = "\d+",
 *     "_access" = "TRUE"
 *   },
 *   options = {
 *     "no_cache" = "TRUE"
 *   }
 * )
 */
public function view($id) { /* … */ }
```

**After (PHP 8 attributes, Drupal 11):**
```php
<?php

use Drupal\Core\Routing\AccessAwareRouteProvider;
use Symfony\Component\Routing\Annotation\Route;

final class ReportController {

  #[Route(
    '/example/report/{id}',
    methods = ['GET'],
    requirements = [
      'id' => '\d+',
      '_access' => 'TRUE',
    ],
    options = [
      'no_cache' => 'TRUE',
    ],
  )]
  public function view(int $id): Response {
    // …
  }
}
```

Important notes:
- Ensure `use Symfony\Component\Routing\Annotation\Route;` is imported.
- `methods` must be an array of uppercase HTTP verbs (`['GET', 'POST']`).
- `_access` is still required for Drupal’s access system (not Symfony’s `access` key).
- Use typed parameters (e.g., `int $id`) instead of untyped `$id` — Symfony 6 auto-casts when the route matches.
- Avoid `@Route` *on class* level in Drupal; prefer `#[Route]` on methods for clarity and flexibility.

For dynamic routes with `routes/example.routing.yml`, prefer `#[Route]` over YAML where possible.

In `services.yml`, use the `factory` key with `@service_id` for service references and `!php/const` or direct values for scalars. Combine with `arguments:` to pass them to the factory method.

**services.yml**
```yaml
services:
  example.report_builder:
    class: 'Drupal\example\Service\ReportBuilder'
    factory: ['@example.report_factory', 'buildReport']
    arguments:
      - '@database'
      - '!php/const:Drupal\example\Service\ReportType::MONTHLY'
```

**Factory class (strict_types enforced):**
```php
<?php

declare(strict_types=1);

namespace Drupal\example\Service;

use Drupal\Core\Database\Connection;

class ReportBuilderFactory {

  public function buildReport(Connection $database, ReportType $type): ReportBuilder {
    return new ReportBuilder($database, $type);
  }
}
```

**Constructor with promoted properties (PHP 8.0+):**
```php
final class ReportBuilder {
  public function __construct(
    private readonly Connection $database,
    private readonly ReportType $type
  ) {}
}
```

Key rules:
- Service references: prefix with `@` (e.g., `@database`).
- Constants: use `!php/const:Fully\Namespaced\Constant::NAME`.
- Avoid `mixed` — use union types and narrow them in factory methods.
- Always enable `declare(strict_types=1)` in all service-related PHP files.
