```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Plugin\MyPluginType;

use Drupal\Core\Plugin\PluginBase;
use Drupal\Core\Renderer\RenderArray;
use Symfony\Component\HttpFoundation\CacheableResponseInterface;

final class MyPlugin extends PluginBase {
  public function build(): array|CacheableResponseInterface {
