// In plugin annotation, keep simple types:
/**
 * @SearchApiKey(
 *   id = "example",
 *   label = @Translation("Example"),
 *   key_type = "string|array" // for documentation only
 * )
 */
class ExampleApiKey implements SearchApiKeyInterface {
  private string|array $key;

  public function __construct(string|array $key) {
    $this->key = $this->normalizeKey($key);
  }

  private function normalizeKey(string|array $key): string {
    return is_array($key) ? implode(',', $key) : $key;
  }

  public function getKey(): string {
    return $this->key;
  }
}
```

