✅ Valid union type (no redundancy):
```php
<?php

declare(strict_types=1);

namespace Drupal\my_module\Plugin;

use Drupal\Core\Plugin\PluginBase;

final class MyPlugin extends PluginBase {
  /**
   * @param array{value?: string|int|float} $configuration
   */
  public function __construct(
    array $configuration = []) {
    parent::__construct($configuration);
  }

  /**
   * @return array{value?: string|int|float}
   */
